     1|/**
     2| * Supabase env sanitizer for the auth/sign-in path.
     3| *
     4| * Root cause this fixes: in Expo Go the EXPO_PUBLIC_SUPABASE_URL and
     5| * EXPO_PUBLIC_SUPABASE_ANON_KEY project variables contain pasted terminal
     6| * text around the real values (labels, local-dev output, multiple tokens).
     7| * Building the Supabase client with those raw strings produces an invalid
     8| * base URL and an invalid `apikey` header, which breaks owner sign-in with
     9| * confusing network/parse errors.
    10| *
    11| * These helpers extract the real hosted Supabase URL and the real anon JWT
    12| * from polluted env values, and fall back to the known production project
    13| * constants when extraction fails. The anon key is a PUBLIC client key
    14| * protected by RLS — embedding the fallback is the standard Supabase pattern.
    15| */
    16|
    17|export const PRODUCTION_SUPABASE_URL = 'https://kvclcdjmjghndxsngfzb.supabase.co';
    18|export const PRODUCTION_SUPABASE_ANON_KEY =
    19|  'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMxOTQwMjcsImV4cCI6MjA4ODc3MDAyN30.OLDwa21VHQNs151AD-8k--_HigQ2d-N7yJfFn5UeNPk';
    20|
    21|const PRODUCTION_SUPABASE_PROJECT_REF = 'kvclcdjmjghndxsngfzb';
    22|
    23|const HOSTED_SUPABASE_URL_PATTERN = /https:\/\/[a-z0-9-]+\.supabase\.co\b/i;
    24|const JWT_PATTERN = /eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+/g;
    25|
    26|declare const __DEV__: boolean | undefined;
    27|
    28|function decodeJwtPayload(token: string): Record<string, unknown> | null {
    29|  try {
    30|    const payloadSegment = token.split('.')[1] ?? '';
    31|    const normalized = payloadSegment.replace(/-/g, '+').replace(/_/g, '/');
    32|    const padded = normalized + '='.repeat((4 - (normalized.length % 4)) % 4);
    33|    const decoded: string = typeof atob === 'function'
    34|      ? atob(padded)
    35|      : Buffer.from(padded, 'base64').toString('utf8');
    36|    return JSON.parse(decoded) as Record<string, unknown>;
    37|  } catch {
    38|    return null;
    39|  }
    40|}
    41|
    42|function isProductionBuild(): boolean {
    43|  return typeof __DEV__ === 'undefined' || !__DEV__;
    44|}
    45|
    46|function extractSupabaseProjectRef(url: string): string | null {
    47|  const match = url.match(/https:\/\/([a-z0-9-]+)\.supabase\.co\b/i);
    48|  return match?.[1] ?? null;
    49|}
    50|
    51|function extractSupabaseJwtRef(token: string): string | null {
    52|  const payload = decodeJwtPayload(token);
    53|  return typeof payload?.ref === 'string' ? payload.ref : null;
    54|}
    55|
    56|/**
    57| * Extract a usable Supabase URL from a possibly polluted env value.
    58| * Preference order:
    59| *   1. A hosted `https://<ref>.supabase.co` URL found anywhere in the string.
    60| *   2. The whole trimmed value when it is a single valid http(s) URL.
    61| *   3. null (caller applies its fallback).
    62| */
    63|export function extractSupabaseUrl(raw: string | undefined | null): string | null {
    64|  const value = (raw ?? '').trim();
    65|  if (!value) return null;
    66|
    67|  const hosted = value.match(HOSTED_SUPABASE_URL_PATTERN);
    68|  if (hosted?.[0]) {
    69|    return hosted[0].replace(/\/$/, '');
    70|  }
    71|
    72|  if (!/\s/.test(value)) {
    73|    try {
    74|      const parsed = new URL(value);
    75|      if (parsed.protocol === 'https:' || parsed.protocol === 'http:') {
    76|        return value.replace(/\/$/, '');
    77|      }
    78|    } catch {
    79|      // fall through
    80|    }
    81|  }
    82|  return null;
