    85|/**
    86| * Extract a usable Supabase anon JWT from a possibly polluted env value.
    87| * Prefers a JWT whose payload declares role "anon"; otherwise the first
    88| * JWT-shaped token found. Returns null when no JWT is present.
    89| */
    90|export function extractSupabaseAnonKey(raw: string | undefined | null): string | null {
    91|  const value = (raw ?? '').trim();
    92|  if (!value) return null;
    93|
    94|  const matches = value.match(JWT_PATTERN) ?? [];
    95|  if (matches.length === 0) return null;
    96|
    97|  for (const candidate of matches) {
    98|    const payload = decodeJwtPayload(candidate);
    99|    if (payload && payload.role === 'anon') {
   100|      return candidate;
   101|    }
   102|  }
   103|  return matches[0] ?? null;
   104|}
