   106|/** Sanitized Supabase URL with production fallback — always a valid URL. */
   107|export function resolveSupabaseUrl(): string {
   108|  const envUrl = extractSupabaseUrl(process.env.EXPO_PUBLIC_SUPABASE_URL);
   109|  const envRef = envUrl ? extractSupabaseProjectRef(envUrl) : null;
   110|  // A hosted Supabase URL pointing to a different project is never safe to use,
   111|  // even in __DEV__ / Expo Go, because it sends real owner credentials to the
   112|  // wrong auth backend and causes the "Invalid API key" failure. Local/self-hosted
   113|  // URLs are still honored when they match the expected shape.
   114|  if (envUrl && envRef && envRef !== PRODUCTION_SUPABASE_PROJECT_REF) {
   115|    console.warn(
