   117|      envUrl,
   118|      'Expected ref:',
   119|      PRODUCTION_SUPABASE_PROJECT_REF,
   120|    );
   121|    return PRODUCTION_SUPABASE_URL;
   122|  }
   123|  if (envUrl) {
   124|    return envUrl;
   125|  }
   126|  return PRODUCTION_SUPABASE_URL;
   127|}
   128|
   129|/** Sanitized Supabase anon key with production fallback — always a valid JWT shape. */
   130|export function resolveSupabaseAnonKey(): string {
   131|  const envKey = extractSupabaseAnonKey(process.env.EXPO_PUBLIC_SUPABASE_ANON_KEY);
   132|  const envRef = envKey ? extractSupabaseJwtRef(envKey) : null;
   133|  // An anon key belonging to a different hosted project is never safe to use,
   134|  // even in __DEV__ / Expo Go, because it mismatches the resolved Supabase URL
   135|  // and produces the "Invalid API key" auth error.
   136|  if (envKey && envRef && envRef !== PRODUCTION_SUPABASE_PROJECT_REF) {
   137|    console.warn(
   138|      '[SupabaseEnv] Ignoring EXPO_PUBLIC_SUPABASE_ANON_KEY because it belongs to a different project:',
   139|      envRef,
   140|      'Expected ref:',
   141|      PRODUCTION_SUPABASE_PROJECT_REF,
   142|    );
   143|    return PRODUCTION_SUPABASE_ANON_KEY;
   144|  }
   145|  if (envKey) {
   146|    return envKey;
   147|  }
   148|  return PRODUCTION_SUPABASE_ANON_KEY;
   149|}
   150|
   151|/** True when either env value was polluted/unusable and a fallback or extraction was applied. */
   152|export function getSupabaseEnvSanitizationReport(): {
   153|  urlRaw: boolean;
   154|  urlSanitized: boolean;
   155|  keyRaw: boolean;
   156|  keySanitized: boolean;
   157|} {
